module top_module (
    input clk,
    input reset,
    output [3:0] count );reg [3:0] count_reg;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset)
            count_reg <= 4'b0000;
        else
            count_reg <= count_reg + 1;
    end

    assign count = count_reg;

endmodule
